import { join } from 'node:path';
import type { ModelMessage } from 'ai';

const SESSION_DIR = '.sessions';
const DEFAULT_SESSION = 'default';

export interface SessionEntry {
  type: 'message';
  timestamp: string;
  message: ModelMessage;
}

export class SessionStore {
  private dir: string;
  private sessionId: string;

  constructor(sessionId: string = DEFAULT_SESSION) {
    this.sessionId = sessionId;
    this.dir = SESSION_DIR;
    if (!existsSync(this.dir)) {
      mkdirSync(this.dir, { recursive: true });
    }
  }

  private get filePath(): string {
    return join(this.dir, `${this.sessionId}.jsonl`);
  }

  append(message: ModelMessage): void {
    const entry: SessionEntry = {
      type: 'message',
      timestamp: new Date().toISOString(),
      message,
    };
    appendFileSync(this.filePath, JSON.stringify(entry) + '\n', 'utf-8');
  }

  appendAll(messages: ModelMessage[]): void {
    for (const msg of messages) {
      this.append(msg);
    }
  }

  load(): ModelMessage[] {
    if (!existsSync(this.filePath)) return [];

    const content = readFileSync(this.filePath, 'utf-8').trim();
    if (!content) return [];

    const messages: ModelMessage[] = [];
    for (const line of content.split('\n')) {
      if (!line.trim()) continue;
      try {
        const entry: SessionEntry = JSON.parse(line);
        if (entry.type === 'message') {
          messages.push(entry.message);
        }
      } catch {
        // skip malformed lines
      }
    }
    return messages;
  }

  exists(): boolean {
    return existsSync(this.filePath);
  }

  getMessageCount(): number {
    return this.load().length;
  }
}

import type { Chunk } from './chunker.js';

export interface StoredChunk extends Chunk {
  embedding: number[];
  addedAt: number;
}

export class VectorStore {
  private chunks: StoredChunk[] = [];

  add(chunk: Chunk, embedding: number[]): void {
    const existing = this.chunks.findIndex(c => c.id === chunk.id);
    if (existing >= 0) {
      this.chunks[existing] = { ...chunk, embedding, addedAt: Date.now() };
    } else {
      this.chunks.push({ ...chunk, embedding, addedAt: Date.now() });
    }
  }

  addBatch(items: Array<{ chunk: Chunk; embedding: number[] }>): void {
    for (const { chunk, embedding } of items) {
      this.add(chunk, embedding);
    }
  }

  getAll(): StoredChunk[] {
    return this.chunks;
  }

  size(): number {
    return this.chunks.length;
  }

  clear(): void {
    this.chunks = [];
  }

  sources(): string[] {
    return [...new Set(this.chunks.map(c => c.source))];
  }
}

