export const bashTool: ToolDefinition = {
  name: 'bash',
  description: '执行 shell 命令并返回输出',
  parameters: {
    type: 'object',
    properties: { 
      command: { type: 'string', description: '要执行的 shell 命令' } 
    },
    required: ['command'],
    additionalProperties: false,
  },
  isConcurrencySafe: false,
  isReadOnly: false,
  maxResultChars: 3000,
  execute: async ({ command }: { command: string }) => {
    // 先测试环境是否支持 shell
    try {
      execSync('echo test', { stdio: 'ignore' });
    } catch {
      return `[bash 不可用] 当前环境不支持 shell 命令。...`;
    }

    // 真正执行命令
    try {
      const output = execSync(command, {
        encoding: 'utf-8',
        timeout: 10000,        // 10秒超时
        maxBuffer: 1024 * 1024, // 1MB 输出上限
        stdio: ['pipe', 'pipe', 'pipe'],
      });
      return output || '(命令执行成功，无输出)';
    } catch (err: any) {
      return `命令执行失败 (exit ${err.status || 1}):\n${err.stderr || err.stdout || err.message}`;
    }
  },
};
```

**关键点：**
- 底层使用 Node.js 的 `execSync` 同步执行
- 有 **10 秒超时限制** 和 **1MB 输出上限**
- 执行前会先检测环境（`echo test`），不支持则给出提示
- 前面执行 `ls` 失败，是因为底层 `execSync` 调用的是 Windows 的 cmd.exe，它不认识 `ls`

